import React from "react";

const attendance = [
  { subject: "Mathematics",  total: 40, attended: 36 },
  { subject: "Physics",      total: 38, attended: 30 },
  { subject: "Chemistry",    total: 42, attended: 40 },
  { subject: "English",      total: 35, attended: 33 },
  { subject: "Core Subject", total: 40, attended: 28 },
];

function Attendance() {
  return (
    <div className="content">
      <h3>✅ Attendance Record</h3>
      <table className="timetable" style={{ marginTop: "15px" }}>
        <thead>
          <tr>
            <th>Subject</th>
            <th>Classes Held</th>
            <th>Attended</th>
            <th>Percentage</th>
            <th>Status</th>
          </tr>
        </thead>
        <tbody>
          {attendance.map((a, i) => {
            const pct = ((a.attended / a.total) * 100).toFixed(1);
            const ok = pct >= 75;
            return (
              <tr key={i}>
                <td>{a.subject}</td>
                <td>{a.total}</td>
                <td>{a.attended}</td>
                <td>{pct}%</td>
                <td style={{ color: ok ? "green" : "red", fontWeight: "bold" }}>
                  {ok ? "✔ Good" : "⚠ Low"}
                </td>
              </tr>
            );
          })}
        </tbody>
      </table>
      <p style={{ marginTop: "12px", fontSize: "13px", color: "#888" }}>
        * Minimum 75% attendance required.
      </p>
    </div>
  );
}

export default Attendance;
